import{_ as o,o as r,c as t,ae as i}from"./chunks/framework.BGHOrOyn.js";const u=JSON.parse('{"title":"Code Review Developer Guide","description":"","frontmatter":{},"headers":[],"relativePath":"software-engineering/principles-and-practices/code-reviews/google-code-review/code-review-developer-guide.md","filePath":"software-engineering/principles-and-practices/code-reviews/google-code-review/code-review-developer-guide.md"}'),a={name:"software-engineering/principles-and-practices/code-reviews/google-code-review/code-review-developer-guide.md"};function s(n,e,l,d,h,c){return r(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="code-review-developer-guide" tabindex="-1">Code Review Developer Guide <a class="header-anchor" href="#code-review-developer-guide" aria-label="Permalink to &quot;Code Review Developer Guide&quot;">​</a></h1><h2 id="eng-practices" tabindex="-1"><a href="https://google.github.io/eng-practices/" target="_blank" rel="noreferrer">eng-practices</a> <a class="header-anchor" href="#eng-practices" aria-label="Permalink to &quot;[eng-practices](https://google.github.io/eng-practices/)&quot;">​</a></h2><h3 id="introduction" tabindex="-1">Introduction <a href="#intro" id="intro"></a> <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction &lt;a href=&quot;#intro&quot; id=&quot;intro&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>A code review is a process where someone other than the author(s) of a piece of code examines that code.</p><p>At Google, we use code review to maintain the quality of our code and products.</p><p>This documentation is the canonical description of Google’s code review processes and policies.</p><p>This page is an overview of our code review process. There are two other large documents that are a part of this guide:</p><ul><li><a href="https://google.github.io/eng-practices/review/reviewer/" target="_blank" rel="noreferrer"><strong>How To Do A Code Review</strong></a>: A detailed guide for code reviewers.</li><li><a href="https://google.github.io/eng-practices/review/developer/" target="_blank" rel="noreferrer"><strong>The CL Author’s Guide</strong></a>: A detailed guide for developers whose CLs are going through review.</li></ul><h3 id="what-do-code-reviewers-look-for" tabindex="-1">What Do Code Reviewers Look For? <a href="#look_for" id="look_for"></a> <a class="header-anchor" href="#what-do-code-reviewers-look-for" aria-label="Permalink to &quot;What Do Code Reviewers Look For? &lt;a href=&quot;#look_for&quot; id=&quot;look_for&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>Code reviews should look at:</p><ul><li><strong>Design</strong>: Is the code well-designed and appropriate for your system?</li><li><strong>Functionality</strong>: Does the code behave as the author likely intended? Is the way the code behaves good for its users?</li><li><strong>Complexity</strong>: Could the code be made simpler? Would another developer be able to easily understand and use this code when they come across it in the future?</li><li><strong>Tests</strong>: Does the code have correct and well-designed automated tests?</li><li><strong>Naming</strong>: Did the developer choose clear names for variables, classes, methods, etc.?</li><li><strong>Comments</strong>: Are the comments clear and useful?</li><li><strong>Style</strong>: Does the code follow our <a href="http://google.github.io/styleguide/" target="_blank" rel="noreferrer">style guides</a>?</li><li><strong>Documentation</strong>: Did the developer also update relevant documentation?</li></ul><p>See <a href="https://google.github.io/eng-practices/review/reviewer/" target="_blank" rel="noreferrer"><strong>How To Do A Code Review</strong></a> for more information.</p><h4 id="picking-the-best-reviewers" tabindex="-1">Picking the Best Reviewers <a href="#best_reviewers" id="best_reviewers"></a> <a class="header-anchor" href="#picking-the-best-reviewers" aria-label="Permalink to &quot;Picking the Best Reviewers &lt;a href=&quot;#best_reviewers&quot; id=&quot;best_reviewers&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>In general, you want to find the <em>best</em> reviewers you can who are capable of responding to your review within a reasonable period of time.</p><p>The best reviewer is the person who will be able to give you the most thorough and correct review for the piece of code you are writing. This usually means the owner(s) of the code, who may or may not be the people in the OWNERS file. Sometimes this means asking different people to review different parts of the CL.</p><p>If you find an ideal reviewer but they are not available, you should at least CC them on your change.</p><h4 id="in-person-reviews-and-pair-programming" tabindex="-1">In-Person Reviews (and Pair Programming) <a href="#in_person" id="in_person"></a> <a class="header-anchor" href="#in-person-reviews-and-pair-programming" aria-label="Permalink to &quot;In-Person Reviews (and Pair Programming) &lt;a href=&quot;#in_person&quot; id=&quot;in_person&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>If you pair-programmed a piece of code with somebody who was qualified to do a good code review on it, then that code is considered reviewed.</p><p>You can also do in-person code reviews where the reviewer asks questions and the developer of the change speaks only when spoken to.</p><h3 id="see-also" tabindex="-1">See Also <a href="#seealso" id="seealso"></a> <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also &lt;a href=&quot;#seealso&quot; id=&quot;seealso&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><ul><li><a href="https://google.github.io/eng-practices/review/reviewer/" target="_blank" rel="noreferrer">How To Do A Code Review</a>: A detailed guide for code reviewers.</li><li><a href="https://google.github.io/eng-practices/review/developer/" target="_blank" rel="noreferrer">The CL Author’s Guide</a>: A detailed guide for developers whose CLs are going through review.</li></ul>',21)])])}const p=o(a,[["render",s]]);export{u as __pageData,p as default};
